# Mathematical utilities module

PI: float = 3.14159

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    return n * factorial(n - 1)

def power(base: float, exp: float) -> float:
    return base ** exp

class Calculator:
    history: list[str]

    def __init__(self):
        self.history = []

    def calculate(self, op: str, a: float, b: float) -> float:
        result: float = 0.0
        if op == "+":
            result = a + b
        elif op == "*":
            result = a * b
        else:
            result = 0.0
        self.history.append(f"{op}: {result}")
        return result

